mapper.select:
    SELECT *, created_at AS createdAt, updated_at AS updatedAt, 
	start_date AS startDate, end_date AS endDate 
	FROM tasks WHERE username = #{username}

    SELECT *, created_at AS createdAt, updated_at AS updatedAt, 
	start_date AS startDate, end_date AS endDate 
	FROM tasks WHERE id = #{id}
